(function(){
  function MiniSwiper(selector, params){
    this.el=typeof selector==='string'?document.querySelector(selector):selector;
    if(!this.el)throw new Error('Swiper container não encontrado');
    this.params=params||{};
    this.events=this.params.on||{};
    this.wrapper=this.el.querySelector('.swiper-wrapper');
    if(!this.wrapper)throw new Error('Swiper wrapper não encontrado');
    this.slides=Array.prototype.slice.call(this.wrapper.children);
    this.activeIndex=Math.max(0,Math.min((this.params.initialSlide||0),Math.max(0,this.slides.length-1)));
    this.previousIndex=this.activeIndex;
    this.destroyed=false;
    this._startX=0;
    this._startY=0;
    this._currentX=0;
    this._currentY=0;
    this._dragging=false;
    this._locked=false;
    this._emit('beforeInit');
    this._setup();
    this.update();
    this._setTransition(0);
    this._setTranslate(-this.activeIndex*this.el.clientWidth);
    this._emit('afterInit');
  }
  MiniSwiper.prototype._emit=function(name){
    if(this.events&&typeof this.events[name]==='function')this.events[name].call(this,this);
  };
  MiniSwiper.prototype.emit=function(name){
    this._emit(name);
  };
  MiniSwiper.prototype._setup=function(){
    var self=this;
    this.el.classList.add('swiper-initialized','swiper-horizontal');
    this.wrapper.style.display='flex';
    this.wrapper.style.height='100%';
    this.wrapper.style.width='100%';
    this.wrapper.style.willChange='transform';
    this.wrapper.style.transitionProperty='transform';
    this.el.addEventListener('touchstart',function(e){self._onStart(e);},{passive:true});
    this.el.addEventListener('touchmove',function(e){self._onMove(e);},{passive:false});
    this.el.addEventListener('touchend',function(e){self._onEnd(e);},{passive:true});
    this.el.addEventListener('touchcancel',function(e){self._onEnd(e);},{passive:true});
    window.addEventListener('resize',function(){self.update();self._setTransition(0);self._setTranslate(-self.activeIndex*self.el.clientWidth);});
  };
  MiniSwiper.prototype._onStart=function(e){
    if(this.destroyed||!e.touches||e.touches.length!==1)return;
    this._startX=e.touches[0].clientX;
    this._startY=e.touches[0].clientY;
    this._currentX=this._startX;
    this._currentY=this._startY;
    this._dragging=false;
    this._locked=false;
    this._setTransition(0);
    this._emit('touchStart');
  };
  MiniSwiper.prototype._onMove=function(e){
    if(this.destroyed||!e.touches||e.touches.length!==1)return;
    this._currentX=e.touches[0].clientX;
    this._currentY=e.touches[0].clientY;
    var dx=this._currentX-this._startX;
    var dy=this._currentY-this._startY;
    if(!this._locked&&Math.max(Math.abs(dx),Math.abs(dy))>8){
      this._locked=true;
      this._dragging=Math.abs(dx)>Math.abs(dy);
    }
    if(!this._dragging)return;
    e.preventDefault();
    var width=this.el.clientWidth||1;
    var resistance=1;
    if((this.activeIndex===0&&dx>0)||(this.activeIndex===this.slides.length-1&&dx<0))resistance=.28;
    this._setTranslate((-this.activeIndex*width)+(dx*resistance));
  };
  MiniSwiper.prototype._onEnd=function(){
    if(this.destroyed)return;
    if(!this._dragging){this._setTransition(180);this._setTranslate(-this.activeIndex*this.el.clientWidth);return;}
    var dx=this._currentX-this._startX;
    var width=this.el.clientWidth||1;
    var threshold=this.params.threshold||20;
    var shouldMove=Math.abs(dx)>Math.max(threshold,width*.12);
    if(shouldMove&&dx<0)this.slideTo(this.activeIndex+1,220);
    else if(shouldMove&&dx>0)this.slideTo(this.activeIndex-1,220);
    else this.slideTo(this.activeIndex,180,false);
  };
  MiniSwiper.prototype._setTransition=function(ms){
    this.wrapper.style.transitionDuration=(ms||0)+'ms';
  };
  MiniSwiper.prototype._setTranslate=function(px){
    this.wrapper.style.transform='translate3d('+px+'px,0,0)';
  };
  MiniSwiper.prototype.update=function(){
    this.slides=Array.prototype.slice.call(this.wrapper.children);
    for(var i=0;i<this.slides.length;i++){
      this.slides[i].style.flex='0 0 100%';
      this.slides[i].style.width='100%';
    }
    this._updateClasses();
  };
  MiniSwiper.prototype._updateClasses=function(){
    for(var i=0;i<this.slides.length;i++){
      this.slides[i].classList.remove('swiper-slide-active','swiper-slide-prev','swiper-slide-next');
      if(i===this.activeIndex)this.slides[i].classList.add('swiper-slide-active');
      if(i===this.activeIndex-1)this.slides[i].classList.add('swiper-slide-prev');
      if(i===this.activeIndex+1)this.slides[i].classList.add('swiper-slide-next');
    }
  };
  MiniSwiper.prototype.slideTo=function(index,speed,emit){
    if(this.destroyed)return;
    var max=Math.max(0,this.slides.length-1);
    var next=Math.max(0,Math.min(index,max));
    var changed=next!==this.activeIndex;
    this.previousIndex=this.activeIndex;
    this.activeIndex=next;
    this._setTransition(typeof speed==='number'?speed:220);
    this._setTranslate(-this.activeIndex*(this.el.clientWidth||1));
    this._updateClasses();
    if(changed&&emit!==false)this._emit('slideChange');
  };
  MiniSwiper.prototype.slideNext=function(speed){this.slideTo(this.activeIndex+1,speed);};
  MiniSwiper.prototype.slidePrev=function(speed){this.slideTo(this.activeIndex-1,speed);};
  MiniSwiper.prototype.destroy=function(){this.destroyed=true;this.el.classList.remove('swiper-initialized','swiper-horizontal');};
  window.Swiper=window.Swiper||MiniSwiper;
})();
